import base64
from Crypto.Cipher import AES, ChaCha20

def decode_data():
    code = base64.b64decode('')
    aes_key = base64.b64decode('94Y4sXUrgo0pLlCHUu4wWAmGUg+Y6L1Qbl2nGebusKA=')
    iv = base64.b64decode('o6l4KjREhFEvbNupL9QNIQ==')
    chacha_key = base64.b64decode('yH9degju0psDLrlbf7DvMkXM7f9qzk/4XrHuQKlECvU=')
    nonce = base64.b64decode('TckyPqhUDhE=')

    cipher_chacha = ChaCha20.new(key=chacha_key, nonce=nonce)
    decrypted_aes_data = cipher_chacha.decrypt(code)

    cipher_aes = AES.new(aes_key, AES.MODE_CBC, iv)
    decrypted_padded = cipher_aes.decrypt(decrypted_aes_data)

    padding_len = decrypted_padded[-1]
    return decrypted_padded[:-padding_len].decode()

exec(decode_data())